function findPeak(nums) {
    let left = 0;
    let right = nums.length - 1;

    while (left < right) {
        let mid = Math.floor((left + right) / 2);

        // If the next element is greater, we are still in the increasing part, so the peak is to the right.
        if (nums[mid] < nums[mid + 1]) {
            left = mid + 1;
        } 
        // If the next element is smaller or equal (since it's strictly bitonic, it must be smaller), 
        // we are at the peak or in the decreasing part, so the peak could be 'mid' or to the left.
        else {
            right = mid;
        }
    }
    return left; // left === right is the index of the peak
}

